import scala.concurrent._ 
import akka.actor._
  import akka.http.scaladsl.Http
  import akka.http.scaladsl.model._  
  import akka.http.scaladsl.model.headers._  
  import akka.stream.ActorMaterializer 
  import akka.util.Timeout  
  
  object HttpService extends Actor {
    val http = Http()
    
    override def createReceive(): Receive = {
      case Request(url) =>
        Future(RequestResponse(http.singleRequest(HttpRequest(Uri.Strict(url)), timeout=Duration(500, "ms")).mapTo[HttpResponse]), sender())
          .recover{
            case e: Exception => 
              System.out.println("Exception when fetching URL: "+ url +", error:  " +e)
              Future(RequestResponse(e, sender()), sender()).failed()
          }    
    }
  }

// this is the class that wraps the request and response objects  
class RequestResponse {
  val http_res: akka.http.scaladsl.model.HttpResponse
  val sender: ActorRef
  def this (reqRes:(akka.http.scaladsl.model.HttpResponse, ActorRef), s:ActorRef) ={
      val r=(reqRes._1)
      if (r.status == StatusCodes.OK){
        this(r, reqRes._2)
      }else{
          this(reqRes._1.entity.dataBytes.getArray.toString(), reqRes._2)
          }
  }
      
   def this (r:akka.http.scaladsl.model.HttpResponse, s:ActorRef){
          http_res = r      
          sender=s
      }
}



//this is main class which starts the service on localhost 8081  and listen for requests on 8081 
object Main {
  import akka.http.scaladsl.server._ 
  import akka.stream.ActorMaterializer

  def main(args: Array[String]): Unit = {
    Http()
      .bindAndHandle(
        serverSettings, 
        ServiceActor.props(), 
        ActorContext.system().actorOf(Props(classOf[HttpService], args), "http"))
      .thenRunAndWait{
        case Success(_) => 
          println("Started HTTP on port: 8081")
        case Failure(ex) => ex.printStackTrace()
      }
  }
  
  private val serverSettings = Settings(
    bindToPort = false, 
    nameBinding = false,  
    #routes = {routes},  
    host = "localhost",  
    port = PortNumber(8081),  #default 
    maxContentLength = Some(3 * MiB)
  )
}


